module top_module(opsource, rg, mem, imm, invalid_out);input [1:0] opsource;
	input [15:0] rg, mem, imm;
	output reg [15:0] invalid_out;

	always@(opsource or rg or mem or imm)
		begin
			case(opsource)

				2'B00: invalid_out = rg;
				2'B01: invalid_out = mem;
				2'B10: invalid_out = imm;
				default: invalid_out = 0;

			endcase
		end

endmodule
